// Обрабатываем статистику из Threads
const insights = $input.item.json;
const post = $('Google Sheets').first().json;

const views = insights.impressions || 0;
const likes = insights.likes || 0;
const comments = insights.comments || 0;
const shares = insights.shares || 0;
const saves = insights.saves || 0;

// Вычисляем метрики
const engagementRate = views > 0 ? ((likes + comments * 2 + shares * 3 + saves * 2) / views * 100) : 0;
const viralityScore = shares > 0 ? (shares / views * 1000) : 0;
const retentionScore = saves > 0 ? (saves / views * 100) : 0;

return {
  json: {
    post_id: post.id,
    threads_post_id: post.threads_post_id,
    pattern_type: post.pattern_type,
    post_type: post.post_type,
    published_at: post.published_at,
    views: views,
    likes: likes,
    comments: comments,
    shares: shares,
    saves: saves,
    engagement_rate: engagementRate,
    virality_score: viralityScore,
    retention_score: retentionScore,
    collected_at: new Date().toISOString()
  }
};

// САМООБУЧАЮЩИЙСЯ АЛГОРИТМ
// Анализируем всю статистику и определяем паттерны успеха

const stats = $input.all();

// 1. Группируем по типам паттернов
const patternStats = {};
stats.forEach(stat => {
  const pattern = stat.pattern_type;
  if (!patternStats[pattern]) {
    patternStats[pattern] = [];
  }
  patternStats[pattern].push(stat);
});

// 2. Вычисляем эффективность каждого паттерна
const patternAnalysis = {};
for (const [pattern, data] of Object.entries(patternStats)) {
  const total = data.length;
  const avgViews = data.reduce((sum, s) => sum + s.views, 0) / total;
  const avgEngagement = data.reduce((sum, s) => sum + s.engagement_rate, 0) / total;
  const avgVirality = data.reduce((sum, s) => sum + s.virality_score, 0) / total;
  const avgRetention = data.reduce((sum, s) => sum + s.retention_score, 0) / total;

  // Комплексный скор успешности (взвешенная формула)
  const successScore = (
    avgViews * 0.25 + 
    avgEngagement * 0.35 + 
    avgVirality * 0.25 + 
    avgRetention * 0.15
  ) / 1000; // Нормализуем

  patternAnalysis[pattern] = {
    total: total,
    avg_views: avgViews,
    avg_engagement: avgEngagement,
    avg_virality: avgVirality,
    avg_retention: avgRetention,
    success_score: successScore
  };
}

// 3. Сортируем паттерны по успешности
const sortedPatterns = Object.entries(patternAnalysis)
  .sort((a, b) => b[1].success_score - a[1].success_score);

// 4. Определяем, какие паттерны нужно усилить, а какие ослабить
const adaptations = [];
const avgScore = sortedPatterns.reduce((sum, [_, data]) => sum + data.success_score, 0) / sortedPatterns.length;

sortedPatterns.forEach(([pattern, data]) => {
  let action = 'maintain';
  let frequencyMultiplier = 1.0;

  if (data.success_score > avgScore * 1.3) {
    action = 'increase_significantly';
    frequencyMultiplier = 2.0;
  } else if (data.success_score > avgScore * 1.1) {
    action = 'increase';
    frequencyMultiplier = 1.5;
  } else if (data.success_score < avgScore * 0.7) {
    action = 'decrease_significantly';
    frequencyMultiplier = 0.3;
  } else if (data.success_score < avgScore * 0.9) {
    action = 'decrease';
    frequencyMultiplier = 0.7;
  }

  adaptations.push({
    pattern: pattern,
    action: action,
    frequency_multiplier: frequencyMultiplier,
    current_performance: data,
    reason: `Success score: ${data.success_score.toFixed(2)} (avg: ${avgScore.toFixed(2)})`
  });
});

// 5. Анализируем временные паттерны (лучшее время для постинга)
const hourlyPerformance = {};
stats.forEach(stat => {
  const hour = new Date(stat.published_at).getHours();
  if (!hourlyPerformance[hour]) {
    hourlyPerformance[hour] = { total: 0, engagement: 0, views: 0 };
  }
  hourlyPerformance[hour].total++;
  hourlyPerformance[hour].engagement += stat.engagement_rate;
  hourlyPerformance[hour].views += stat.views;
});

const bestHours = Object.entries(hourlyPerformance)
  .map(([hour, data]) => ({
    hour: parseInt(hour),
    avg_engagement: data.engagement / data.total,
    avg_views: data.views / data.total
  }))
  .sort((a, b) => b.avg_engagement - a.avg_engagement)
  .slice(0, 3);

// 6. Анализируем длину постов
const lengthAnalysis = {
  short: stats.filter(s => (s.post_text?.length || 0) < 100),
  medium: stats.filter(s => (s.post_text?.length || 0) >= 100 && (s.post_text?.length || 0) < 200),
  long: stats.filter(s => (s.post_text?.length || 0) >= 200)
};

const lengthPerformance = {};
for (const [length, data] of Object.entries(lengthAnalysis)) {
  if (data.length > 0) {
    lengthPerformance[length] = {
      count: data.length,
      avg_engagement: data.reduce((sum, s) => sum + s.engagement_rate, 0) / data.length
    };
  }
}

const bestLength = Object.entries(lengthPerformance)
  .sort((a, b) => b[1].avg_engagement - a[1].avg_engagement)[0];

return {
  json: {
    analysis_date: new Date().toISOString(),
    total_posts_analyzed: stats.length,
    pattern_analysis: patternAnalysis,
    adaptations: adaptations,
    best_posting_hours: bestHours,
    best_post_length: bestLength ? bestLength[0] : 'medium',
    avg_performance: {
      views: stats.reduce((sum, s) => sum + s.views, 0) / stats.length,
      engagement_rate: stats.reduce((sum, s) => sum + s.engagement_rate, 0) / stats.length,
      virality_score: stats.reduce((sum, s) => sum + s.virality_score, 0) / stats.length
    },
    recommendations: {
      top_patterns: sortedPatterns.slice(0, 3).map(([p, d]) => p),
      avoid_patterns: sortedPatterns.slice(-2).map(([p, d]) => p),
      optimal_posting_times: bestHours.map(h => `${h.hour}:00`),
      recommended_length: bestLength ? bestLength[0] : 'medium'
    }
  }
};

// Генерируем обновленные промпты на основе анализа
const analysis = $input.item.json;

// Создаем конфигурацию для обновления промптов
const promptsConfig = {
  version: new Date().toISOString(),
  adaptations: analysis.adaptations,
  patterns: {},
  meta: {
    best_hours: analysis.best_posting_hours.map(h => h.hour),
    best_length: analysis.best_post_length,
    avg_performance: analysis.avg_performance
  }
};

// Для каждого паттерна создаем инструкции
analysis.adaptations.forEach(adaptation => {
  promptsConfig.patterns[adaptation.pattern] = {
    frequency_multiplier: adaptation.frequency_multiplier,
    action: adaptation.action,
    performance: adaptation.current_performance,
    enabled: adaptation.frequency_multiplier > 0.5,
    priority: adaptation.frequency_multiplier > 1.5 ? 'high' : adaptation.frequency_multiplier > 1.0 ? 'medium' : 'low'
  };
});

return {
  json: {
    config: promptsConfig,
    filename: `prompts-config-${new Date().toISOString().split('T')[0]}.json`,
    content: JSON.stringify(promptsConfig, null, 2)
  }
};

